package com.vidaysalud.veterinaria.consultaservicio.repository;import com.vidaysalud.veterinaria.consultaservicio.model.Consulta;import org.springframework.data.jpa.repository.JpaRepository;import java.util.*;public interface ConsultaRepository extends JpaRepository<Consulta,Integer>{List<Consulta>findByIdMascota(Integer idMascota);List<Consulta>findByIdVeterinario(Integer idVeterinario);Optional<Consulta>findByIdCita(Integer idCita);}